const raw = $json.output?.[0]?.content?.[0]?.text;

if (!raw) {
  throw new Error("OpenAI output text not found. Code node must receive data from OpenAI node.");
}

const ai = JSON.parse(raw);

const originalLead = $("Webhook").first().json.body;

return [
  {
    json: {
      name: originalLead.name,
      company: originalLead.company,
      message: originalLead.message,
      score: ai.score,
      status: ai.status,
      reason: ai.reason
    }
  }
];

const lead = $json.body;

const msg = (lead.message || "").toLowerCase();

let score = 1;
let status = "not_qualified";
let reason = "not relevant or unclear request";

const hasLabubu =
  msg.includes("labubu") ||
  msg.includes("лабубу");

const wantsBuy =
  msg.includes("хочу купить") ||
  msg.includes("куплю") ||
  msg.includes("заказать") ||
  msg.includes("готов оплатить") ||
  msg.includes("готов забрать");

const wantsOriginal =
  msg.includes("оригинал") ||
  msg.includes("оригинальную") ||
  msg.includes("оригинальный");

const hasDetails =
  msg.includes("син") ||
  msg.includes("красн") ||
  msg.includes("зел") ||
  msg.includes("фиолет") ||
  msg.includes("больш") ||
  msg.includes("малень") ||
  msg.includes("цвет") ||
  msg.includes("размер") ||
  msg.includes("коробк");

if (hasLabubu && wantsBuy && wantsOriginal && hasDetails) {
  score = 10;
  status = "qualified";
  reason = "clear purchase intent for original Labubu with details";
} else if (hasLabubu && wantsBuy && wantsOriginal) {
  score = 9;
  status = "qualified";
  reason = "clear purchase intent for original Labubu";
} else if (hasLabubu && wantsBuy) {
  score = 8;
  status = "qualified";
  reason = "clear Labubu purchase intent";
} else if (
  hasLabubu &&
  (
    msg.includes("сколько") ||
    msg.includes("цена") ||
    msg.includes("есть") ||
    msg.includes("налич")
  )
) {
  score = 6;
  status = "qualified";
  reason = "interested in Labubu but purchase intent is not fully clear";
} else if (hasLabubu) {
  score = 5;
  status = "qualified";
  reason = "mentions Labubu but intent is weak";
} else if (
  msg.includes("игрушк") ||
  msg.includes("подарок") ||
  msg.includes("ребён") ||
  msg.includes("ребен")
) {
  score = 4;
  status = "not_qualified";
  reason = "general toy interest without Labubu";
} else {
  score = 2;
  status = "not_qualified";
  reason = "request is unrelated to Labubu";
}

return [
  {
    json: {
      name: lead.name,
      company: lead.company,
      message: lead.message,
      score,
      status,
      reason
    }
  }
];
